def withdraw(balance, daily_spent, amount):
    if amount <= 0:
        return (False, 'Amount must be positive')
    if amount % 20 != 0:
        return (False, 'Amount must be a multiple of $20')
    if amount > balance:
        return (False, 'Insufficient funds')
    if daily_spent + amount > 500:
        return (False, 'Exceeds daily withdrawal limit of $500')
    return (True, f'Successfully withdrew ${amount}')
